import numpy as np
from scipy.stats import norm

class DeltaHedger:
    def __init__(self, spot: float, strike: float, rate: float, vol: float, T: float, is_call: bool, quantity: int):
        self.spot = spot
        self.strike = strike
        self.rate = rate
        self.vol = vol
        self.T = T
        self.is_call = is_call
        self.quantity = quantity
        self.hedge_shares = 0

    def delta(self) -> float:
        d1 = (np.log(self.spot/self.strike) + (self.rate + 0.5*self.vol**2)*self.T) / (self.vol*np.sqrt(self.T))
        if self.is_call:
            return norm.cdf(d1) * self.quantity
        return (norm.cdf(d1) - 1) * self.quantity

    def hedge_position(self) -> float:
        return -self.delta()

    def rebalance(self, new_spot: float) -> dict:
        self.spot = new_spot
        new_hedge = self.hedge_position()
        trade = new_hedge - self.hedge_shares
        self.hedge_shares = new_hedge
        return {'trade': trade, 'new_hedge': new_hedge, 'portfolio_delta': self.delta() + new_hedge}

