import numpy as np
from scipy.stats import norm

class OptionGreeks:
    def __init__(self, spot: float, strike: float, rate: float, vol: float, T: float, is_call: bool):
        self.S = spot
        self.K = strike
        self.r = rate
        self.vol = vol
        self.T = T
        self.is_call = is_call

    def d1(self) -> float:
        return (np.log(self.S/self.K) + (self.r + 0.5*self.vol**2)*self.T) / (self.vol*np.sqrt(self.T))

    def d2(self) -> float:
        return self.d1() - self.vol*np.sqrt(self.T)

    def delta(self) -> float:
        if self.is_call:
            return norm.cdf(self.d1())
        return norm.cdf(self.d1()) - 1

    def gamma(self) -> float:
        return norm.pdf(self.d1()) / (self.S * self.vol * np.sqrt(self.T))

    def vega(self) -> float:
        return self.S * np.sqrt(self.T) * norm.pdf(self.d1()) * 0.01

    def theta(self) -> float:
        term1 = -self.S * norm.pdf(self.d1()) * self.vol / (2*np.sqrt(self.T))
        if self.is_call:
            term2 = -self.r * self.K * np.exp(-self.r*self.T) * norm.cdf(self.d2())
        else:
            term2 = self.r * self.K * np.exp(-self.r*self.T) * norm.cdf(-self.d2())
        return (term1 + term2) / 365

