import numpy as np
from scipy.stats import norm

class GammaHedger:
    def __init__(self, portfolio_delta: float, portfolio_gamma: float):
        self.portfolio_delta = portfolio_delta
        self.portfolio_gamma = portfolio_gamma

    def hedge_with_option(self, option_delta: float, option_gamma: float) -> dict:
        if abs(option_gamma) < 1e-10:
            return {'error': 'Option has zero gamma'}
        option_quantity = -self.portfolio_gamma / option_gamma
        new_delta = self.portfolio_delta + option_quantity * option_delta
        underlying_shares = -new_delta
        return {
            'option_quantity': option_quantity,
            'underlying_shares': underlying_shares,
            'final_delta': 0,
            'final_gamma': self.portfolio_gamma + option_quantity * option_gamma
        }

