import numpy as np
from scipy.optimize import minimize

class MultiGreekHedger:
    def __init__(self, portfolio_greeks: dict):
        self.portfolio = portfolio_greeks

    def optimize_hedge(self, hedge_greeks: list, targets: dict) -> dict:
        n = len(hedge_greeks)
        def objective(q):
            cost = sum(abs(q[i]) * hedge_greeks[i].get('cost', 1) for i in range(n))
            delta = self.portfolio['delta'] + sum(q[i] * hedge_greeks[i]['delta'] for i in range(n))
            gamma = self.portfolio['gamma'] + sum(q[i] * hedge_greeks[i]['gamma'] for i in range(n))
            vega = self.portfolio.get('vega', 0) + sum(q[i] * hedge_greeks[i].get('vega', 0) for i in range(n))
            penalty = 1000 * ((delta - targets.get('delta', 0))**2 + (gamma - targets.get('gamma', 0))**2 + (vega - targets.get('vega', 0))**2)
            return cost + penalty
        result = minimize(objective, np.zeros(n), method='SLSQP')
        achieved = {
            'delta': self.portfolio['delta'] + sum(result.x[i] * hedge_greeks[i]['delta'] for i in range(n)),
            'gamma': self.portfolio['gamma'] + sum(result.x[i] * hedge_greeks[i]['gamma'] for i in range(n))
        }
        return {'quantities': result.x, 'cost': result.fun, 'achieved_greeks': achieved}
